targets.expr:
histogram_quantile(
  0.95,
  sum by (le) (
    rate(queue_wait_latency_seconds_bucket{tier="FREE"}[5m])
  )
)
-
histogram_quantile(
  0.95,
  sum by (le) (
    rate(queue_wait_latency_seconds_bucket{tier="VIP"}[5m])
  )
)

(
  sum by (tier) (
    inference_queue_depth
  ) > bool 0
)
*
on (tier)
(
  sum by (tier) (
    rate(processed_requests_total[5m])
  ) == bool 0
)

sum by (model, version) (
  rate(nv_inference_request_success[1m])
)
/
clamp_min(
  sum by (model, version) (
    rate(nv_inference_exec_count[1m])
  ),
  0.001
)
